assert(({
    &&& (0 <= r1 < self_.keys@.len())
    &&& (self_.greatest_lower_bound_spec(*iter, KeyIterator::new_spec(self_.keys@[r1 as int])))
    &&& (0 <= r2 < self_.keys@.len())
    &&& (self_.greatest_lower_bound_spec(*iter, KeyIterator::new_spec(self_.keys@[r2 as int])))
}) ==> det_greatest_lower_bound_index_equal(r1, r2)) by {
    K::cmp_properties();
    K::zero_properties();
    if (0 <= r1 < self_.keys@.len())
       && (self_.greatest_lower_bound_spec(*iter, KeyIterator::new_spec(self_.keys@[r1 as int])))
       && (0 <= r2 < self_.keys@.len())
       && (self_.greatest_lower_bound_spec(*iter, KeyIterator::new_spec(self_.keys@[r2 as int]))) {
        let k1 = self_.keys@[r1 as int];
        let k2 = self_.keys@[r2 as int];
        let glb1 = KeyIterator::<K>::new_spec(k1);
        let glb2 = KeyIterator::<K>::new_spec(k2);

        // Both keys lie in self_@ because dom == keys@.to_set().
        assert(self_.keys@.contains(k1));
        assert(self_.keys@.contains(k2));
        assert(self_@.contains_key(k1));
        assert(self_@.contains_key(k2));

        // Step 1: show k1 == k2 by contradicting k1 != k2.
        if k1 != k2 {
            if iter.is_end_spec() {
                // iter.above(_) is true (iter is end), so property 2 fires for both glbs.
                assert(iter.above(k1));
                assert(iter.above(k2));
                assert(KeyIterator::new_spec(k2) != glb1);
                assert(KeyIterator::new_spec(k1) != glb2);
                assert(glb1.above(k2));
                assert(glb2.above(k1));
                // glb_i.k.is_Some(), so above gives a strict ordering.
                assert(k2.cmp_spec(k1).lt());
                assert(k1.cmp_spec(k2).lt());
                assert(false);
            } else {
                // !iter.is_end_spec(): use property 3 (existence of hi witness)
                // and the gap predicate. By connected, k1 < k2 or k2 < k1.
                if k1.cmp_spec(k2).lt() {
                    let hi1 = choose|hi: KeyIterator<K>|
                        #[trigger] self_.gap(glb1, hi)
                            && #[trigger] KeyIterator::between(glb1, *iter, hi);
                    assert(self_.gap(glb1, hi1));
                    assert(KeyIterator::between(glb1, *iter, hi1));
                    // KeyIterator::new_spec(k2) lies strictly between glb1 and hi1:
                    //   glb1 < new_spec(k2) since k1 < k2,
                    //   new_spec(k2) = glb2 <= iter < hi1.
                    assert(glb1.lt_spec(KeyIterator::new_spec(k2)));
                    assert(KeyIterator::new_spec(k2).lt_spec(hi1));
                    // The gap forall (triggered by self_@.contains_key(*ki.get()))
                    // then forces k2 to be absent from self_@, contradicting above.
                    assert(!self_@.contains_key(*KeyIterator::<K>::new_spec(k2).get()));
                    assert(false);
                } else {
                    assert(k2.cmp_spec(k1).lt());
                    let hi2 = choose|hi: KeyIterator<K>|
                        #[trigger] self_.gap(glb2, hi)
                            && #[trigger] KeyIterator::between(glb2, *iter, hi);
                    assert(self_.gap(glb2, hi2));
                    assert(KeyIterator::between(glb2, *iter, hi2));
                    assert(glb2.lt_spec(KeyIterator::new_spec(k1)));
                    assert(KeyIterator::new_spec(k1).lt_spec(hi2));
                    assert(!self_@.contains_key(*KeyIterator::<K>::new_spec(k1).get()));
                    assert(false);
                }
            }
        }
        assert(k1 == k2);

        // Step 2: from keys@[r1] == keys@[r2] and sortedness, r1 == r2.
        if (r1 as int) < (r2 as int) {
            assert(self_.keys@[r1 as int].cmp_spec(self_.keys@[r2 as int]).lt());
            assert(false);
        }
        if (r2 as int) < (r1 as int) {
            assert(self_.keys@[r2 as int].cmp_spec(self_.keys@[r1 as int]).lt());
            assert(false);
        }
        assert(r1 == r2);
        assert(det_greatest_lower_bound_index_equal(r1, r2));
    }
};
